import boto3
import json
import time

class SQSWorker:
    def __init__(self, queue_name):
        self.sqs = boto3.client('sqs')
        self.queue_url = self.sqs.get_queue_url(QueueName=queue_name)['QueueUrl']

    def process_message(self, message_body):
        try:
            message_data = json.loads(message_body)
            message_type = message_data.get('type')
            
            if message_type == 'type1':
                self.handle_type1(message_data)
            elif message_type == 'type2':
                self.handle_type2(message_data)
            else:
                self.handle_default(message_data)
        except Exception as e:
            print(f"Error processing message: {str(e)}")

    def handle_type1(self, data):
        print('Processing type1 message:', data)

    def handle_type2(self, data):
        print('Processing type2 message:', data)
        
    def handle_default(self, data):
        print('Processing default message type:', data)

    def poll_messages(self):
        while True:
            response = self.sqs.receive_message(
                QueueUrl=self.queue_url,
                MaxNumberOfMessages=10,
                WaitTimeSeconds=20
            )
            
            messages = response.get('Messages', [])
            for message in messages:
                self.process_message(message['Body'])
                self.sqs.delete_message(
                    QueueUrl=self.queue_url,
                    ReceiptHandle=message['ReceiptHandle']
                )
            time.sleep(1)

